<template>
  <div>
    <div
      v-if="$route.path.indexOf('editor') === -1"
      class="shoppingguidenotification"
    >
      <el-row>
        <el-col>
          <el-select
            v-model="searchData.status"
            placeholder="請選擇"
          >
            <el-option
              v-for="item in stateOptions"
              :key="item.value"
              :label="item.label"
              :value="item.value"
            />
          </el-select>
          <el-input
            v-model="searchData.title"
            class="input-b"
            placeholder="請輸入通知名稱"
          >
            <el-button
              slot="append"
              icon="el-icon-search"
              @click="handelClickSearch"
            />
          </el-input>
          <el-button
            type="primary"
            icon="el-icon-circle-plus-outline"
            @click="handelClickAdd"
          >
            新增通知
          </el-button>
        </el-col>
      </el-row>
      <!-- table -->
      <el-card>
        <el-table
          v-loading="loadingTable"
          :data="tableData"
          style="width: 100%"
        >
          <el-table-column
            prop="title"
            label="通知標題"
          />
          <el-table-column
            prop="created"
            label="發生時間"
          >
            <template slot-scope="scope">
              {{ timestampToTime(scope.row.created) }}
            </template>
          </el-table-column>
          <el-table-column
            prop="updated"
            label="最後一次發送時間"
          >
            <template slot-scope="scope">
              {{ timestampToTime(scope.row.last_sent_time) }}
            </template>
          </el-table-column>
          <el-table-column
            prop="withdraw"
            label="發送狀態"
          >
            <template slot-scope="scope">
              {{ scope.row.status | sendingState }}
            </template>
          </el-table-column>
          <el-table-column
            fixed="right"
            label="操作"
            width="200"
          >
            <template slot-scope="scope">
              <el-button
                type="text"
                @click="
                  () =>
                    $router.push({
                      path: matchHidePage('editor'),
                      query: { id: scope.row.notice_id }
                    })
                "
              >
                編輯
              </el-button>
              <el-button
                v-if="scope.row.status != 1"
                type="text"
                @click="
                  () => {
                    temporary = scope.row
                    showSeeModule = true
                  }
                "
              >
                查看
              </el-button>
              <el-button
                v-if="scope.row.status != 2"
                type="text"
                @click="
                  () => {
                    temporary = scope.row
                    showSendModule = true
                  }
                "
              >
                發送
              </el-button>
              <el-button
                v-if="scope.row.status == 2"
                type="text"
                @click="handelClickRevoke(scope.row)"
              >
                撤回發送
              </el-button>
            </template>
          </el-table-column>
        </el-table>
        <el-pagination
          class="content-padded content-center"
          background
          :current-page="paging.page"
          :page-sizes="[10, 20, 50, 100]"
          :page-size="paging.page_size"
          layout="total, sizes, prev, pager, next, jumper"
          :total="paging.total_count"
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
        />
      </el-card>
      <!-- 查看 -->
      <el-dialog
        title="查看通知發送狀態"
        :visible.sync="showSeeModule"
        width="700"
        :before-close="
          () => {
            showSeeModule = false
          }
        "
      >
        <el-form
          v-loading="loading"
          :model="seeDataForm"
          label-width="100px"
        >
          <el-form-item
            label="通知時間："
          >
            {{ seeDataForm.last_sent_time | formatDataTime }}
            {{ seeDataForm.status | sendingState }}
          </el-form-item>
          <el-form-item
            v-if="seeDataForm.all_distributor == 1"
            label="通知店鋪："
          >
            全部
          </el-form-item>
          <el-form-item
            v-if="seeDataForm.all_distributor == 0"
            label="通知店鋪："
          >
            <el-tag
              v-for="(item, index) in seeDataForm.distributors"
              :key="index"
              size="size"
            >
              {{
                item.name
              }}
            </el-tag>
          </el-form-item>
        </el-form>
      </el-dialog>
      <!-- 發送通知 -->
      <el-dialog
        v-loading="loading"
        title="發送通知"
        :visible.sync="showSendModule"
        width="700"
        :before-close="
          () => {
            showSendModule = false
          }
        "
      >
        <div class="flex">
          <div class="label">
            選擇通知門店：
          </div>
          <div>
            <el-radio
              v-model="sendDataForm.radio"
              label="1"
            >
              全部門店
            </el-radio>
            <el-radio
              v-model="sendDataForm.radio"
              label="2"
            >
              選擇門店
            </el-radio>
          </div>
        </div>
        <div class="flex ma-t">
          <div class="label">
            通知門店：
          </div>
          <div v-if="sendDataForm.radio == 1">
            全部
          </div>
          <div v-if="sendDataForm.radio == 2">
            <div>
              <ul class="flex">
                <li
                  v-for="item in distributor_info"
                  :key="item.distributor_id"
                  class="ma-r"
                >
                  <el-tag>{{ item.name }}</el-tag>
                </li>
              </ul>
            </div>
            <el-button
              class="ma-t"
              type="primary"
              @click="
                () => {
                  ;(distributorVisible = true), (setDistributorStatus = true)
                }
              "
            >
              選擇店鋪
            </el-button>
          </div>
        </div>
        <span
          slot="footer"
          class="dialog-footer"
        >
          <el-button @click="showSendModule = false">取 消</el-button>
          <el-button
            type="primary"
            @click="handelClickSendOut"
          >確 定</el-button>
        </span>
      </el-dialog>
      <DistributorSelect
        :store-visible="distributorVisible"
        :is-valid="true"
        :get-status="setDistributorStatus"
        @chooseStore="handelClickDistributor"
        @closeStoreDialog="distributorVisible = false"
      />
    </div>
    <router-view />
  </div>
</template>
<script>
import { mapGetters } from 'vuex'
import DistributorSelect from '@/components/storeListSelect'

import {
  getSalespersonoticeList,
  delSalespersonoticeWithdrawnotice,
  setSalespersonoticeSendnotice,
  getSalespersonoticeDetail
} from '@/api/marketing'

export default {
  components: {
    DistributorSelect
  },
  provide () {
    return {
      refresh: this.fetchList
    }
  },
  filters: {
    sendingState (v) {
      if (v == 1) {
        return '未發送'
      }
      if (v == 2) {
        return ' 已發送'
      }
      return '已撤回'
    }
  },
  data () {
    return {
      loadingTable: false,
      loading: false,
      stateOptions: [
        {
          value: '0',
          label: '全部'
        },
        {
          value: '1',
          label: '已發送'
        },
        {
          value: '2',
          label: '未發送'
        },
        {
          value: '3',
          label: '已撤回'
        }
      ],
      searchData: {
        status: '0', //狀體
        title: '' //標題
      },
      tableData: [],
      paging: {
        //分頁
        page: 1,
        page_size: 10,
        total_count: 0
      },
      showSeeModule: false, //查看
      seeDataForm: {
        radio: '1',
        shop: ''
      },
      showSendModule: false, //發送通知
      sendDataForm: {
        radio: '1'
      },

      distributorVisible: false, //選擇店鋪組件
      setDistributorStatus: false,
      distributor_info: [],
      distributor_id: [],

      temporary: null //臨時存儲
    }
  },
  watch: {
    showSeeModule (val) {
      if (val) {
        this._getSalespersonoticeDetail()
      }
      console.log('val', val)
    }
  },
  computed: {
    ...mapGetters(['wheight'])
  },
  mounted () {
    this.handelClickSearch()
  },
  methods: {
    resetPage () {
      this.paging = {
        page: 1,
        page_size: 10,
        total_count: 0
      }
    },

    fetchList () {
      this.resetPage()
      this.handelClickSearch()
    },

    /**
     * 搜尋
     * */
    async handelClickSearch () {
      let { page, page_size } = this.paging
      let { title, status } = this.searchData

      let params = {
        page,
        page_size,
        title,
        status
      }
      this.loadingTable = true

      let { data } = await getSalespersonoticeList(params)

      this.tableData = data.data.list

      this.paging.total_count = data.data.total_count

      this.loadingTable = false
    },

    /**
     * 分頁
     * */
    handleCurrentChange (val) {
      this.paging.page = val
      this.handelClickSearch()
    },
    // 時間戳轉日期格式
    timestampToTime (timestamp) {
      var date = new Date(timestamp * 1000) //時間戳為10位需*1000，時間戳為13位的話不需乘1000
      var YY = date.getFullYear() + '-'
      var MM = (date.getMonth() + 1 < 10 ? '0' + (date.getMonth() + 1) : date.getMonth() + 1) + '-'
      var DD = date.getDate() < 10 ? '0' + date.getDate() : date.getDate()
      var hh = (date.getHours() < 10 ? '0' + date.getHours() : date.getHours()) + ':'
      var mm = (date.getMinutes() < 10 ? '0' + date.getMinutes() : date.getMinutes()) + ':'
      var ss = date.getSeconds() < 10 ? '0' + date.getSeconds() : date.getSeconds()
      return YY + MM + DD + ' ' + hh + mm + ss
    },

    /**
     * 新增消息通知
     * */

    handelClickAdd (id) {
      this.$router.push({ path: this.matchHidePage('editor') })
    },

    /**
     * 撤回發送
     * */
    handelClickRevoke (row) {
      let notice_id = row.notice_id
      this.checkWithdrawnotice(async () => {
        let data = await delSalespersonoticeWithdrawnotice({ notice_id })

        this.resetPage()

        this.handelClickSearch()

        this.$message({
          type: 'success',
          message: '撤回成功!'
        })
      })
    },
    checkWithdrawnotice (callback) {
      this.$confirm('撤回後，對應店鋪的導購將無法再看到次通知?', '提示', {
        confirmButtonText: '確定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        callback()
      })
    },

    /**
     * 選擇店鋪
     * */
    handelClickDistributor (data) {
      this.distributorVisible = false
      if (data === null || data.length <= 0) return
      this.distributor_info = data
      let distributor_id = []
      for (var i = 0; i < data.length; i++) {
        if (distributor_id.indexOf(Number(data[i].distributor_id)) < 0) {
          distributor_id.push(Number(data[i].distributor_id))
        }
      }
      this.distributor_id = distributor_id
    },

    /**
     * 發送導購通知
     * */
    async handelClickSendOut () {
      let params = {
        notice_id: this.temporary.notice_id,
        distributor_id:
          this.sendDataForm.radio == '1' ? 'all' : JSON.parse(JSON.stringify(this.distributor_id))
      }
      this.loading = true

      if (params.distributor_id !== 'all' && this.distributor_id.length === 0) {
        this.$message.error('請選擇店鋪')
        return
      }
      this.loading = false

      console.log('params', params)

      // return;
      this.showSendModule = false

      let { data } = await setSalespersonoticeSendnotice(params)

      this.$message({
        message: '發送成功',
        type: 'success'
      })

      this.distributor_id = []
      this.sendDataForm.radio = '1'
      this.handelClickSearch()
    },

    /**
     * 獲取導購通知
     * */
    async _getSalespersonoticeDetail () {
      this.loading = true

      let { data } = await getSalespersonoticeDetail({
        notice_id: this.temporary.notice_id,
        with_log: 1
      })
      this.seeDataForm = data.data
      this.loading = false
      console.log('_getSalespersonoticeDetail', data)
    },
    handleSizeChange (val) {
      this.paging.page = 1
      this.paging.page_size = val
      this.handelClickSearch()
    }
  }
}
</script>

<style scoped lang="scss">
.shoppingguidenotification {
  .flex {
    display: flex;
  }
  &-header {
    height: 73px;
  }
  .label {
    width: 105px;
  }
  .ma-t {
    margin-top: 30px;
  }
  .ma-r {
    margin-right: 20px;
  }
}
